<?php namespace App\Services\Security; class SecurityScanner { protected array $maliciousPatterns = [ 'sql_injection' => '/(UNION SELECT|DROP TABLE|INSERT INTO|--|OR 1=1)/i', 'xss_attacks' => '/(<script.*?>|<.*?on\w+=.*?|javascript:)/i', 'system_exec' => '/(exec\(|shell_exec\(|passthru\(|system\(|eval\()/i' ]; public function scanText(string $input): array { $report = ['is_safe' => true, 'threats' => []]; foreach ($this->maliciousPatterns as $type => $pattern) { if (preg_match($pattern, $input)) { $report['is_safe'] = false; $report['threats'][] = $type; } } return $report; } public function scanFile(string $filePath): array { if (!file_exists($filePath) || !is_readable($filePath)) { return ['is_safe' => false, 'error' => 'File not accessible']; } $content = file_get_contents($filePath); return $this->scanText($content); } }